"""
MKT Original Language Commentary — John chapters 17–18
Run: python3 scripts/zc-original-john-17-18.py

Source data used:
- data/interlinear/john.json (chapters 17–18 tokens)
- data/translation/glossary-greek.json (semantic ranges, dispute levels)
- data/translation/draft/mediating/john.json (MKT text for reference)

Key decisions in this range:
- "the Evangelist" continues as authorial designation throughout
- δοξάζω (17:1): mutual glorification is the structural frame of the prayer;
  aorist imperatives signal definite, historical acts not ongoing sentiments
- αἰώνιος (17:3): dispute_level 3 — "age-enduring/eternal"; the commentary
  notes the dispute without forcing the reader to a conclusion
- ἕν (17:11,21,22,23): neuter singular throughout — unity of kind/being, not
  numerical identity; the grammar matters theologically
- Ἅγιε πάτερ (17:11): unique address in the NT; paired later with Πάτερ δίκαιε
  (17:25) — both divine attributes anchor the prayer's two petitions
- ἁγιάζω (17:17,19): both ceremonial consecration and moral purification are
  in range; the Evangelist's use in v.19 is priestly (Jesus consecrating himself
  as the offering)
- τοῦ πονηροῦ (17:15): masculine, not neuter — "the evil one" (personal),
  not "evil" (abstract)
- ἐγώ εἰμι (18:5–8): the absolute I-AM without predicate, producing the dramatic
  falling backward; same construction as 8:24,28,58
- ἀνθρακιά (18:18,21:9): charcoal fire — rare word, appears only twice in the
  NT, both in John and both at moments of dramatic irony for Peter
- παρρησία (18:20): "openly/publicly" — the legal register: Jesus claims his
  teaching has been entirely public, contrary to the charge of seditious secrecy
- βασιλεία (18:36): "kingdom not of this world" — ἐκ followed by genitive of
  source/origin: the kingdom's origin is not from this-world order, though it
  operates within it
- σημαίνων ποίῳ θανάτῳ (18:32): the Evangelist's fulfillment note uses the verb
  σημαίνω (to signal/indicate), the same verb used in Rev 1:1 for symbolic
  revelation — crucifixion must come as the lifted-up death of the Son of Man
- Μάλχος (18:10): Malchus is named only in John; the specificity is a marker
  of eyewitness or well-sourced tradition
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


JOHN = {
  "17": {
    "1": '<p><strong>ταῦτα ἐλάλησεν</strong> — "these things he spoke" — aorist, closing the farewell discourse (chs. 14–16) before the prayer begins. <strong>ἐπάρας τοὺς ὀφθαλμοὺς αὐτοῦ εἰς τὸν οὐρανόν</strong> — "having lifted his eyes toward heaven" — a posture of direct address attested in synagogue prayer and the Psalms; Jesus speaks to the Father face-to-face, not through an intermediary formula. <strong>ἐλήλυθεν ἡ ὥρα</strong> — "the hour has come" — perfect tense, <em>elēlythen</em>: the arrival of the hour is a completed event whose results now stand. This is the hour repeatedly deferred in the Gospel (2:4; 7:30; 8:20) and now declared present. The two <em>doxazō</em> imperatives — "glorify your Son, that the Son may glorify you" — are aorist, marking the mutual glorification as a single completed act, not an ongoing disposition.</p>',

    "2": '<p><strong>καθὼς ἔδωκας αὐτῷ ἐξουσίαν πάσης σαρκός</strong> — "just as you gave him authority over all flesh." <em>Exousia</em> (G1849) is delegated authority — a granted right, not mere capacity. <em>Pasēs sarkos</em> — "all flesh" — the Semitic idiom for all humanity without exception (cf. Gen 6:12; Isa 40:5). The scope is universal; the exercise is particular: "so that to all those you have given him, he might give eternal life." <strong>δέδωκας</strong> (perfect, "you have given") — the giving stands as a completed and present reality; Jesus prays over an already-constituted people.</p>',

    "3": '<p><strong>αὕτη δέ ἐστιν ἡ αἰώνιος ζωή</strong> — "And this is eternal life." The Evangelist — or Jesus within the prayer — offers a formal definition, a rare move in the Gospel. <strong>αἰώνιος</strong> (G166, dispute_level 3): the adjective derives from <em>aiōn</em> (age/era), and carries both qualitative ("of the age to come," the divine life-order) and quantitative ("without end") senses. The MKT renders it "eternal" but the qualitative dimension is primary: this is the life of the new age, not merely endless duration. <strong>ἵνα γινώσκωσίν σε</strong> — "that they may know you" — present subjunctive, ongoing knowing, not a single act of recognition. <em>Ginōskō</em> in John carries relational freight: the same word used for the knowing between Father and Son (10:15), and between husband and wife in the LXX. <strong>τὸν μόνον ἀληθινὸν θεόν</strong> — "the only true God" — <em>alēthinos</em> (G228) means "real/genuine" as against counterfeit; not merely the only God numerically, but the God who is authentically what God is.</p>',

    "4": '<p><strong>ἐγώ σε ἐδόξασα ἐπὶ τῆς γῆς</strong> — "I glorified you on the earth" — aorist, looking back over the entire ministry as a completed act. The initiative is Jesus\'s: he brought glory to the Father, not the reverse. <strong>τὸ ἔργον τελειώσας</strong> — "having completed/perfected the work" — aorist participle of <em>teleioō</em> (G5048), to bring to its destined end. The same root appears in the great cry from the cross, <em>tetelestai</em> (19:30): what is here prayed in anticipation ("having finished the work you gave me") is declared accomplished at death. The prayer is proleptic — Jesus speaks of the cross as already complete.</p>',

    "5": '<p><strong>νῦν δόξασόν με σύ, πάτερ, παρὰ σεαυτῷ τῇ δόξῃ ᾗ εἶχον</strong> — "And now, Father, glorify me alongside yourself with the glory that I had." <em>Para seautō</em> — "alongside yourself / in your presence" — the preposition denotes proximity and personal relation, not merely location. <strong>πρὸ τοῦ τὸν κόσμον εἶναι παρὰ σοί</strong> — "before the world was, alongside you" — the pre-existence of the Son stated explicitly: the glory requested is a return to a state that antedated creation. The construction <em>pro tou + infinitive</em> marks temporal priority: the Son\'s shared glory precedes cosmogony. This is the most direct statement of the Son\'s pre-existence in the prayer and one of the clearest in the Gospel (cf. 1:1; 8:58).</p>',

    "6": '<p><strong>ἐφανέρωσά σου τὸ ὄνομα τοῖς ἀνθρώποις</strong> — "I revealed your name to the people." <em>Phaneroō</em> (G5319, aorist) is the Evangelist\'s verb for making visible what is otherwise concealed (cf. 1:31; 2:11; 9:3). "Your name" in Jewish understanding is not a label but a disclosure of character and presence — the divine <em>shem</em>. Jesus claims to have made the Father\'s name-reality visible through his ministry. <strong>οὓς δέδωκάς μοι ἐκ τοῦ κόσμου</strong> — "those you gave me out of the world" — perfect, the Father\'s giving is a standing reality. <strong>τὸν λόγον σου τετήρηκαν</strong> — "they have kept your word" — perfect, their keeping also stands. Two perfects balance each other: the gift given and the reception completed.</p>',

    "7": '<p><strong>νῦν ἔγνωκαν ὅτι πάντα ὅσα δέδωκάς μοι παρὰ σοῦ εἰσίν</strong> — "Now they have known that all things, whatever you have given me, are from you." <em>Egnōkan</em> — perfect of <em>ginōskō</em>: they have arrived at and now rest in this knowledge. The insight is singular: everything Jesus has — his words, works, authority, disciples — originates from the Father. The chain of origin (Father → Son → disciples) is the disciples\'s growing theological understanding that the prayer consolidates.</p>',

    "8": '<p><strong>τὰ ῥήματα ἃ ἔδωκάς μοι δέδωκα αὐτοῖς</strong> — "the words you gave me I have given to them." The distinction between <em>rhēma</em> (individual spoken word/utterance) and <em>logos</em> (the Word as self-disclosure or teaching body) matters here: <em>rhēmata</em> are the specific verbal utterances transmitted down the chain. <strong>ἔλαβον</strong> (aorist, "they received"), <strong>ἔγνωσαν</strong> (aorist, "they knew"), <strong>ἐπίστευσαν</strong> (aorist, "they believed") — three aorists in sequence mark three completed acts that together constitute the disciples\' reception: they received the words, recognized their origin, and committed to it by faith.</p>',

    "9": '<p><strong>οὐ περὶ τοῦ κόσμου ἐρωτῶ</strong> — "I am not praying for the world." The present tense <em>erōtō</em> ("I am asking") marks this as the active scope of the prayer at this moment, not an absolute exclusion — the Evangelist has already shown Jesus speaking of his love for the world (3:16; 12:32). The restriction is strategic: the prayer focuses on those already given to him, the visible community who will carry the mission. <strong>περὶ ὧν δέδωκάς μοι</strong> — "for those you have given me" — perfect, the given ones are constituted. <strong>σοί εἰσιν</strong> — "they are yours" — predicate without emphasis; their belonging to the Father is the ground of the prayer.</p>',

    "10": '<p><strong>καὶ τὰ ἐμὰ πάντα σά ἐστιν καὶ τὰ σὰ ἐμά</strong> — "and all mine is yours, and yours mine." The mutual possession is stated with remarkable compression — no verb in the second clause, the reciprocity made absolute. This mutual ownership of all things is the ontological ground of the Son\'s prayer: he prays as one who shares everything with the Father. <strong>δεδόξασμαι ἐν αὐτοῖς</strong> — "I have been glorified in them" — perfect passive: the disciples are already the locus where the Son\'s glory has landed and remains visible. The prayer is not for glory not yet given but for the protection of a glory already present in a fragile vessel.</p>',

    "11": '<p><strong>Ἅγιε πάτερ</strong> — "Holy Father" — a unique address in the NT. Jesus elsewhere addresses God simply as <em>Pater</em> or <em>Abba</em>; the addition of <em>Hagie</em> (G40, "holy") creates a title that invokes the divine attribute that most fully belongs to God alone. Holiness here grounds the petition: the one who is holy is asked to guard those set apart for him. <strong>τήρησον αὐτοὺς ἐν τῷ ὀνόματί σου</strong> — "keep them in/by your name" — <em>tēreō</em> (G5083) is "guard/keep watch over" — protective keeping, not mere maintenance. <strong>ἵνα ὦσιν ἕν καθὼς ἡμεῖς</strong> — "that they may be one as we are." <em>Hen</em> — neuter, "one thing" — unity of kind, not numerical identity (which would be <em>heis</em>, masculine). The grammar preserves both unity and distinction in the divine relationship, and the disciples\' unity is modeled on it, not identical to it.</p>',

    "12": '<p><strong>ἐγὼ ἐτήρουν αὐτοὺς ἐν τῷ ὀνόματί σου</strong> — "I was keeping them in your name" — imperfect, continuous past action: the keeping was Jesus\'s ongoing activity throughout the ministry. <strong>οὐδεὶς ἐξ αὐτῶν ἀπώλετο εἰ μὴ ὁ υἱὸς τῆς ἀπωλείας</strong> — "none of them was lost except the son of destruction." <em>Apōleia</em> (G684) — destruction, perdition — gives Judas his epithet: he is defined by the outcome, the one who was heading toward destruction. The exception clause (<em>ei mē</em>) does not cancel the claim of keeping; it marks Judas as outside the group being described. <strong>ἵνα ἡ γραφὴ πληρωθῇ</strong> — "that the scripture might be fulfilled" — the fulfillment formula anchors the loss of Judas within providential necessity; the Evangelist probably has Ps 41:9 in view (cf. 13:18).</p>',

    "13": '<p><strong>νῦν δὲ πρὸς σὲ ἔρχομαι</strong> — "But now I am coming to you" — present tense, proleptic: Jesus speaks of the cross-and-return as an imminent present movement. <strong>ἵνα ἔχωσιν τὴν χαρὰν τὴν ἐμὴν πεπληρωμένην ἐν ἑαυτοῖς</strong> — "that they may have my joy fulfilled in themselves." <em>Peplerōmenēn</em> — perfect passive participle, "having been made full/complete": the joy the disciples are to share is not an installment but the complete measure of Jesus\'s own joy. The farewell discourse in ch. 16 promised that joy-in-sorrow would be converted to a joy no one can take; this prayer confirms the goal.</p>',

    "14": '<p><strong>ἐγὼ δέδωκα αὐτοῖς τὸν λόγον σου</strong> — "I have given them your word" — perfect, the giving stands. <strong>ὁ κόσμος ἐμίσησεν αὐτούς</strong> — "the world hated them" — aorist, the hatred is a historical response already incurred. <strong>ὅτι οὐκ εἰσὶν ἐκ τοῦ κόσμου καθὼς ἐγὼ οὐκ εἰμὶ ἐκ τοῦ κόσμου</strong> — "because they are not out of the world just as I am not out of the world." The <em>ek</em> preposition marks source or origin: the disciples no longer derive their identity and orientation from the world-system, just as Jesus does not. This is the theological ground of the world\'s hostility.</p>',

    "15": '<p><strong>οὐκ ἐρωτῶ ἵνα ἄρῃς αὐτοὺς ἐκ τοῦ κόσμου</strong> — "I am not asking that you take them out of the world." The prayer explicitly refuses withdrawal. <strong>ἀλλ᾽ ἵνα τηρήσῃς αὐτοὺς ἐκ τοῦ πονηροῦ</strong> — "but that you keep them from the evil one." <em>Tou ponērou</em> — genitive of <em>ponēros</em> (G4190): the masculine form is decisive — this is "the evil one" (a person), not "evil" (an abstract). The same construction appears in the Lord\'s Prayer (Matt 6:13). The petition is not for isolation but for guarded engagement: in the world but protected from the one who rules it (cf. 12:31; 14:30; 16:11).</p>',

    "16": '<p><strong>ἐκ τοῦ κόσμου οὐκ εἰσίν, καθὼς ἐγὼ ἐκ τοῦ κόσμου οὐκ εἰμί</strong> — verbatim repetition of v. 14b. In the Evangelist\'s style, repetition is rarely decorative; it marks the thesis being held constant while the surrounding argument develops. Here the repeated declaration of the disciples\' non-world-derivation frames the petition of v. 15 on both sides, ensuring the reader understands the basis for the protection request.</p>',

    "17": '<p><strong>ἁγίασον αὐτοὺς ἐν τῇ ἀληθείᾳ</strong> — "Sanctify them in/by the truth." <em>Hagiazō</em> (G37, aorist imperative): the verb\'s semantic range spans ceremonial consecration (setting apart for holy use), ritual purification, and moral transformation. All three are operative here: the disciples are being set apart from the world-system (v. 16), purified for service, and morally shaped by what is true. <strong>ὁ λόγος ὁ σὸς ἀλήθειά ἐστιν</strong> — "your word is truth." Not "true" (<em>alēthēs</em>) but "truth" (<em>alētheia</em>) without the article — the word does not merely correspond to truth; it is the substance of truth. The Evangelist has already identified Jesus as "the truth" (14:6); now the Father\'s word shares that characterization.</p>',

    "18": '<p><strong>καθὼς ἐμὲ ἀπέστειλας εἰς τὸν κόσμον, κἀγὼ ἀπέστειλα αὐτοὺς εἰς τὸν κόσμον</strong> — "Just as you sent me into the world, I also sent them into the world." The sending of the disciples is explicitly modeled on the Father\'s sending of the Son: same verb (<em>apostellō</em>, G649), same direction (into the world), same syntax. This is the Fourth Gospel\'s theological grounding of mission: the disciples\' apostolate participates in the structure of the divine sending, not merely in its content. The aorist "I also sent" treats the commissioning as already accomplished — cf. 20:21.</p>',

    "19": '<p><strong>ὑπὲρ αὐτῶν ἐγὼ ἁγιάζω ἐμαυτόν</strong> — "for their sake I sanctify myself." The formula is priestly and sacrificial: the high priest consecrates himself before presenting an offering on behalf of others. Jesus is here both priest and offering — he sets himself apart for the purpose of his own sacrifice. <em>Hagiazō emauton</em> — the reflexive "sanctify myself" — occurs nowhere else in the NT; it is a unique claim. <strong>ἵνα ὦσιν καὶ αὐτοὶ ἡγιασμένοι ἐν ἀληθείᾳ</strong> — "that they too may be sanctified in truth" — perfect passive participle <em>hēgiasmenoi</em>: the result of his self-consecration is their standing consecration, an accomplished state, not merely an ongoing process. <em>En alētheia</em> here is probably instrumental: by means of truth (the word, cf. v. 17), and/or in genuine reality (as against merely ceremonial consecration).</p>',

    "20": '<p><strong>Οὐ περὶ τούτων δὲ ἐρωτῶ μόνον</strong> — "I do not pray only for these." The scope of the prayer expands beyond the immediate disciples to encompass all future believers. <strong>ἀλλὰ καὶ περὶ τῶν πιστευόντων διὰ τοῦ λόγου αὐτῶν</strong> — "but also for those who believe through their word." <em>Dia tou logou autōn</em> — through their word/message: the chain of transmission is explicit — Father → Son → disciples → their word → future believers. The present participle <em>pisteuontōn</em> ("those believing") includes all who come to faith through the apostolic message, which by the Evangelist\'s own account (20:31) includes the Gospel itself.</p>',

    "21": '<p><strong>ἵνα πάντες ἕν ὦσιν</strong> — "that all may be one." <em>Hen</em> — neuter, as in v. 11 — the same grammatical form maintains consistency: the unity prayed for is participatory, not numerical. <strong>καθὼς σύ, πάτερ, ἐν ἐμοί, κἀγὼ ἐν σοί</strong> — "just as you, Father, are in me and I in you" — the mutual indwelling (<em>perikhōrēsis</em> in later theological terminology) is the model, not just the analogy. <strong>ἵνα καὶ αὐτοὶ ἐν ἡμῖν ὦσιν</strong> — "that they also may be in us" — the goal is believers\' participation in the Trinitarian fellowship, not mere social unity. <strong>ἵνα ὁ κόσμος πιστεύῃ</strong> — the unity of believers is missionary in purpose: it is to be visible enough to convince the world of the Son\'s divine sending.</p>',

    "22": '<p><strong>κἀγὼ τὴν δόξαν ἣν δέδωκάς μοι δέδωκα αὐτοῖς</strong> — "And I have given them the glory that you have given me." Both verbs are perfect: the Father\'s giving of glory to the Son and the Son\'s giving of that glory to the disciples are both completed and standing. The glory given to the disciples is not merely honor or reputation but the self-revealing radiance of the divine presence — the same <em>doxa</em> that the Evangelist says "we beheld" (1:14). <strong>ἵνα ὦσιν ἕν καθὼς ἡμεῖς ἕν</strong> — "that they may be one as we are one" — neuter throughout; the unity given by glory is qualitative, not numerical fusion.</p>',

    "23": '<p><strong>ἐγὼ ἐν αὐτοῖς καὶ σὺ ἐν ἐμοί, ἵνα ὦσιν τετελειωμένοι εἰς ἕν</strong> — "I in them and you in me, that they may be perfected into one." <em>Teteleiōmenoi eis hen</em> — perfect passive participle with <em>eis</em> of goal or result: "brought to completion into oneness." The verb <em>teleioō</em> (G5048) carries its characteristic Johannine sense of completing, bringing to intended purpose. The unity is not static but the telos toward which the community is being directed. <strong>ἵνα γινώσκῃ ὁ κόσμος ὅτι σύ με ἀπέστειλας</strong> — "so that the world may know that you sent me" — the missionary claim again: the visible completion of the community is the apologetic argument for the Son\'s divine origin.</p>',

    "24": '<p><strong>θέλω</strong> — "I will / I desire" — not the prayer-verb <em>erōtaō</em> used throughout (vv. 9, 15, 20) but the volitional <em>thelō</em> (G2309): "I will it, I want it." The shift marks this verse as something other than petition — it is a statement of the Son\'s determined will addressed to the Father. <strong>ἵνα ὅπου εἰμὶ ἐγὼ κἀκεῖνοι ὦσιν μετ᾽ ἐμοῦ</strong> — "that where I am, they may also be with me" — the eschatological goal: the disciples\' presence with Jesus where he is (cf. 14:3: "that where I am you may also be"). <strong>ἵνα θεωρῶσιν τὴν δόξαν τὴν ἐμήν</strong> — "that they may behold my glory" — <em>theōreō</em> (G2334), the seeing of prolonged direct observation, not a glance. The glory is the pre-existent glory of v. 5. The petition is for the disciples\' eschatological vision of what they could not fully see during the ministry.</p>',

    "25": '<p><strong>Πάτερ δίκαιε</strong> — "Righteous Father" — a second unique address in the prayer, balancing "Holy Father" in v. 11. <em>Dikaios</em> (G1342): just, righteous — the attribute that governs v. 25\'s claim: God\'s justice will vindicate the disciples\' knowledge of Jesus over against the world\'s ignorance. <strong>ὁ κόσμος σε οὐκ ἔγνω</strong> — "the world did not know you" — aorist, a settled verdict on the world\'s history of not-knowing. <strong>ἐγὼ δέ σε ἔγνων</strong> — "but I knew you" — same aorist, a simple historical fact about the Son\'s consistent knowing of the Father. <strong>καὶ οὗτοι ἔγνωσαν ὅτι σύ με ἀπέστειλας</strong> — "and these knew that you sent me" — the disciples stand with the Son in knowing, differentiated from the world.</p>',

    "26": '<p><strong>καὶ ἐγνώρισα αὐτοῖς τὸ ὄνομά σου καὶ γνωρίσω</strong> — "and I have made your name known to them, and I will make it known." The movement from aorist (<em>egnōrisa</em>) to future (<em>gnōrisō</em>) is significant: Jesus\'s disclosure of the Father\'s name is both a completed ministry achievement and a continuing work — the making-known will continue through the Spirit (cf. 16:13–15) and through the community\'s witness. <strong>ἵνα ἡ ἀγάπη ἣν ἠγάπησάς με ἐν αὐτοῖς ᾖ κἀγὼ ἐν αὐτοῖς</strong> — "that the love with which you loved me may be in them, and I in them." The prayer closes with the ultimate goal: the Father\'s love for the Son is to take up residence in the disciples. <em>Agapē</em> (G26) here is not the disciples\' love but the divine love itself — the inner-Trinitarian love — relocating into the believing community. The final phrase "and I in them" is the mechanism: Christ\'s indwelling is how the divine love enters and remains.</p>'
  },
  "18": {
    "1": '<p><strong>τοῦ χειμάρρου τῶν Κέδρων</strong> — "the Kidron torrent/valley." <em>Cheimarros</em> (G5493) denotes a wadi — a seasonal streambed that runs with water in winter rains and dries in summer. The name <em>Kedrōn</em> derives from the Hebrew <em>Qidrōn</em> (darkness/black), associated with the brook David crossed when fleeing Absalom (2 Sam 15:23) — a detail likely not accidental to the Evangelist. <strong>κῆπος</strong> — "garden" — the Synoptics name it Gethsemane; John uses the garden detail, which will recur at the burial (19:41) and resurrection (20:15). The garden as the site of the arrest and the tomb as a garden signals an Edenic counternarrative: the second Adam entering the garden where the first Adam fell.</p>',

    "2": '<p><strong>ᾔδει δὲ καὶ Ἰούδας ὁ παραδιδοὺς αὐτόν τὸν τόπον</strong> — "Now Judas, the one betraying him, also knew the place." The participle <em>ho paradidous</em> — "the one delivering over/betraying" — is present, characterizing Judas by his ongoing function, not merely the act. <em>Paradidōmi</em> (G3860) carries the double register of handing over (to authorities) and betrayal (of trust); the Evangelist uses it without softening. The explanation — Jesus had met there often with his disciples — underscores that the garden was a place of intimacy now turned into a trap by insider knowledge.</p>',

    "3": '<p><strong>τὴν σπεῖραν</strong> — "the cohort/detachment." <em>Speira</em> (G4686) is the Greek term for a Roman military unit, normally a cohort of 480–600 soldiers; in practice "a detachment" here may indicate a maniple or smaller unit. The presence of Roman soldiers (alongside temple police and officials) from the outset in John\'s account is theologically significant: the arrest is under the joint authority of Roman empire and Jewish leadership — the powers of this world act together. <strong>μετὰ φανῶν καὶ λαμπάδων καὶ ὅπλων</strong> — "with torches and lanterns and weapons" — the detail is ironic: they come with artificial light to arrest the Light of the world, with weapons to arrest the one who will lay down his life voluntarily.</p>',

    "4": '<p><strong>Ἰησοῦς οὖν εἰδὼς πάντα τὰ ἐρχόμενα ἐπ᾽ αὐτόν</strong> — "Jesus, therefore, knowing all the things coming upon him." <em>Eidōs</em> — perfect participle of <em>oida</em> (G1492), the verb of intuitive or complete knowing, not the relational <em>ginōskō</em>. The Evangelist stresses Jesus\'s sovereign foreknowledge: the arrest does not happen to a surprised victim but to one who foreknew it and chose it. <strong>ἐξῆλθεν</strong> — "went out" — Jesus takes the initiative, coming to meet the arresting party rather than waiting to be seized.</p>',

    "5": '<p><strong>Ἰησοῦν τὸν Ναζωραῖον</strong> — "Jesus the Nazarene" — the geographical designation used at the arrest, the trial placard (19:19), and the post-resurrection announcement (20:15; cf. Acts 2:22). <strong>ἐγώ εἰμι</strong> — the absolute I-AM without predicate. In Greek, "I am he" would be <em>egō eimi autos</em> or simply <em>egō</em>; the bare <em>egō eimi</em> carries the register of the divine self-disclosure formula of Exod 3:14 LXX and the Isaianic "I AM" declarations (Isa 43:10 LXX: <em>egō eimi</em>). The Evangelist has used it at 8:24, 8:28, 8:58; here it is the operative term that causes the arrest party to fall back. The parenthetical note about Judas standing with them maximizes the irony: the betrayer is present when the divine name drops them to the ground.</p>',

    "6": '<p><strong>ἀπῆλθον εἰς τὰ ὀπίσω καὶ ἔπεσαν χαμαί</strong> — "they went back and fell to the ground." <em>Chamai</em> (G5476, "to the ground") appears only here and at 9:6 (where Jesus spits on the ground to make clay); the rare word links the healing of the blind man and the arrest — divine power operates at ground level. The falling backward of the armed detachment at the utterance of <em>egō eimi</em> is a theophany response: comparison with the prostrations at divine appearances in the OT (Dan 8:17; Ezek 1:28; Rev 1:17) makes clear the Evangelist\'s intent. The arresting party cannot arrest Jesus; he gives himself over.</p>',

    "7": '<p><strong>Τίνα ζητεῖτε</strong> — the question repeated verbatim from v. 4. The Evangelist\'s repetition is deliberate: after the display of divine authority in the I-AM and the falling backward, Jesus asks again the same question. The soldiers and officials must answer again — "Jesus the Nazarene" — and receive the same reply. The repetition is a literary device of patient sovereignty: Jesus controls the arrest scene even while submitting to it.</p>',

    "8": '<p><strong>εἶπον ὑμῖν ὅτι ἐγώ εἰμι</strong> — "I told you that I am he." The I-AM formula is now restated plainly. <strong>εἰ οὖν ἐμὲ ζητεῖτε, ἄφετε τούτους ὑπάγειν</strong> — "if then you seek me, let these go" — <em>aphete</em> (aorist imperative of <em>aphiēmi</em>, G863): release, let go. The Evangelist portrays Jesus as negotiating the terms of the arrest, securing the disciples\' freedom as a condition — a detail unique to the Fourth Gospel. This connects to the "good shepherd" motif of ch. 10: the shepherd gives his life and the sheep go free.</p>',

    "9": '<p><strong>ἵνα πληρωθῇ ὁ λόγος ὃν εἶπεν</strong> — "that the word he had spoken might be fulfilled." The Evangelist uses the standard fulfillment formula (<em>hina plērōthē</em>) but here applies it not to a scripture but to Jesus\'s own prior word (17:12: "I have not lost one of those you gave me"). Jesus\'s words have the same fulfillment-authority as Scripture — a significant claim that runs through the Johannine passion narrative.</p>',

    "10": '<p><strong>Σίμων οὖν Πέτρος ἔχων μάχαιραν εἵλκυσεν αὐτήν</strong> — "Simon Peter therefore, having a sword, drew it." <em>Machaira</em> (G3162): a short sword or large knife, the standard personal sidearm. <strong>τοῦ ἀρχιερέως τὸν δοῦλον</strong> — "the high priest\'s servant." Only the Fourth Gospel names the servant: <strong>Μάλχος</strong> (G3124). The naming is a marker of concrete tradition — the Evangelist or his source knew who Malchus was. The specific ear named (<em>tēn dexian</em>, the right ear) adds further precision. <strong>ἀπέκοψεν αὐτοῦ τὸ ὠτάριον τὸ δεξιόν</strong> — "cut off his right ear" — <em>ōtarion</em> (G5621): diminutive of <em>ous</em>, perhaps "ear-lobe" rather than the whole ear.</p>',

    "11": '<p><strong>Βάλε τὴν μάχαιραν εἰς τὴν θήκην</strong> — "Put your sword into the sheath." The command is a present-tense imperative (<em>bale</em> can also be aorist), but the gesture is unmistakable: the sword is sheathed. <strong>τὸ ποτήριον ὃ δέδωκέν μοι ὁ πατήρ, οὐ μὴ πίω αὐτό</strong> — "the cup that the Father has given me, shall I not drink it?" <em>Potērion</em> (G4221) — the cup is the Gethsemane language present in the Synoptics (Matt 26:39; Mark 14:36; Luke 22:42) but absent from John\'s Gethsemane-equivalent. The Evangelist introduces it here instead, as Jesus accepts the arrest: the cup metaphor for divinely-assigned suffering and death (cf. Ps 75:8; Isa 51:17; Jer 25:15). The double negative <em>ou mē piō</em> (strong negation with subjunctive) is a rhetorical question expecting the answer "of course I will drink it."</p>',

    "12": '<p><strong>ἡ σπεῖρα καὶ ὁ χιλίαρχος καὶ οἱ ὑπηρέται τῶν Ἰουδαίων</strong> — "the cohort and the commander and the officers of the Jews" — three parties to the arrest: Roman soldiers, their commanding officer (<em>chiliarchos</em>, G5506, lit. "commander of a thousand," a tribune), and Jewish temple police. The binding of Jesus (<em>ἔδησαν</em>, aorist: they bound him) occurs immediately — the legal formality of custody asserted. Jesus goes bound through the rest of the trial narrative.</p>',

    "13": '<p><strong>Ἄνναν πρῶτον</strong> — "to Annas first." The sequence — Annas before Caiaphas — is unique to John. Annas had been high priest from AD 6–15; Caiaphas (his son-in-law) held the office AD 18–36. Annas retained enormous political influence and is addressed or referred to as high priest by both Luke (Luke 3:2; Acts 4:6) and John. The appearance before Annas is a preliminary examination — the factual hearing before the formal proceeding at Caiaphas\'s house. <strong>ὁ πενθερὸς τοῦ Καϊάφα</strong> — "the father-in-law of Caiaphas" — a kinship detail explaining the first transfer.</p>',

    "14": '<p><strong>ἦν δὲ Καϊάφας ὁ συμβουλεύσας τοῖς Ἰουδαίοις ὅτι συμφέρει ἕνα ἄνθρωπον ἀπολέσθαι ὑπὲρ τοῦ λαοῦ</strong> — "It was Caiaphas who had advised the Jews that it was expedient for one man to die for the people." The Evangelist reaches back to 11:50, where Caiaphas\'s pragmatic counsel was identified as inadvertent prophecy. <em>Sympherō</em> (G4851): "to be expedient/profitable" — the political calculus of one death for national preservation. The Evangelist quotes this without comment, allowing the irony to work: the man who authorized the arrest is the one whose political prophecy the trial is now fulfilling in ways he did not intend.</p>',

    "15": '<p><strong>ὁ ἄλλος μαθητής</strong> — "the other disciple" — the Beloved Disciple, unnamed throughout the Gospel (13:23; 19:26; 20:2; 21:7,20). <strong>γνωστὸς τῷ ἀρχιερεῖ</strong> — "known to the high priest" — <em>gnōstos</em> (G1110): one who is known, a recognized acquaintance. How the Beloved Disciple had this connection is unexplained; the tradition is taken as known to the original readers. This connection allows him to enter the <em>aulē</em> (courtyard/palace) of the high priest — the inner residential compound, not a public space.</p>',

    "16": '<p><strong>εἱστήκει δὲ ὁ Πέτρος πρὸς τῇ θύρᾳ ἔξω</strong> — "Peter was standing at the door outside" — pluperfect <em>heistēkei</em>: he had taken up his standing position. The door between outside and inside becomes the spatial emblem of Peter\'s ambiguous position — he wants to follow but cannot enter, exactly as Jesus told him (13:36–38). <strong>ἡ παιδίσκη ἡ θυρωρός</strong> — "the girl who kept the door" — a female doorkeeper. The first challenge to Peter comes from the least threatening social figure imaginable: a servant girl. The irony of the arrest scene\'s powerful men falling at <em>egō eimi</em> while Peter caves at a doorkeeper\'s question is structurally intentional.</p>',

    "17": '<p><strong>μὴ καὶ σὺ ἐκ τῶν μαθητῶν εἶ τοῦ ἀνθρώπου τούτου</strong> — "You aren\'t also one of the disciples of this man, are you?" The construction with <em>mē</em> signals a question expecting a negative answer — the girl herself frames it as unlikely. <strong>οὐκ εἰμί</strong> — "I am not" — Peter\'s first denial is a stark reversal of the I-AM formula Jesus used in vv. 5–8. Where Jesus\'s <em>egō eimi</em> (I am) was the divine self-disclosure that felled soldiers, Peter\'s <em>ouk eimi</em> (I am not) is the self-protective denial. The Evangelist\'s juxtaposition is deliberate and devastating.</p>',

    "18": '<p><strong>ἀνθρακιάν</strong> — "a charcoal fire." <em>Anthrakia</em> (G439) appears only twice in the NT: here (18:18) and at 21:9, where the risen Jesus has prepared a charcoal fire for the disciples on the shore. The rare word is a Johannine echo-marker: Peter warms himself at a charcoal fire during the denial; the risen Christ will meet Peter at a charcoal fire for the restoration. The verbal connection between the two scenes is not accidental. <strong>ἦν δὲ ψῦχος</strong> — "it was cold" — one of the Gospel\'s vivid physical details; the night cold explains the fire and sets the atmospheric register of the trial scenes.</p>',

    "19": '<p><strong>ὁ οὖν ἀρχιερεὺς ἠρώτησεν τὸν Ἰησοῦν περὶ τῶν μαθητῶν αὐτοῦ καὶ περὶ τῆς διδαχῆς αὐτοῦ</strong> — "The high priest then questioned Jesus about his disciples and about his teaching." Annas\'s two questions — about followers (potential insurgent movement) and teaching (possible blasphemy or sedition) — are the standard preliminary categories of a Jewish judicial inquiry. <em>Didachē</em> (G1322): teaching, doctrine. The Evangelist does not identify this as a formal Sanhedrin proceeding — the formal judgment was Caiaphas\'s (11:50) and the legal death-verdict will be in 19:6–7. This is an interrogation.</p>',

    "20": '<p><strong>ἐγὼ παρρησίᾳ λελάληκα τῷ κόσμῳ</strong> — "I have spoken openly to the world." <em>Parrēsia</em> (G3954) — literally "all-speech," frank and public disclosure — is the legal claim Jesus makes: nothing was said in private that is not on public record. <em>Lelalēka</em> — perfect, "I have spoken and this speaking stands." <strong>ἐν συναγωγῇ καὶ ἐν τῷ ἱερῷ</strong> — "in synagogue and in the temple" — the two primary public institutions of Jewish religious life; Jesus\'s teaching venues were the most scrutinized and crowded spaces available. <strong>ἐν κρυπτῷ ἐλάλησα οὐδέν</strong> — "in secret I spoke nothing" — the privacy charge implicit in Annas\'s questioning is denied outright. Jesus is not a clandestine teacher of a secret sect.</p>',

    "21": '<p><strong>τί με ἐρωτᾷς; ἐρώτησον τοὺς ἀκηκοότας</strong> — "Why do you question me? Ask those who have heard me." Jesus\'s reply invokes the standard Jewish legal principle: testimony must come from witnesses (<em>Deut 19:15</em>), not from self-incrimination. <em>Tous akēkootas</em> — perfect participle: "those who have heard and still have that hearing." The witnesses exist; the court should call them. This is a legally astute response, not mere deflection: Jesus is pointing to the correct procedure under Torah.</p>',

    "22": '<p><strong>ῥάπισμα ἔδωκεν</strong> — "gave a slap/blow." <em>Rapisma</em> (G4475): a blow with an open hand or rod — in rabbinic legal contexts, striking a party under judicial examination was a contempt of procedure if the examination had not yet concluded. <strong>Οὕτως ἀποκρίνῃ τῷ ἀρχιερεῖ</strong> — "Is this how you answer the high priest?" — the official\'s intervention treats Jesus\'s appeal to witnesses as impudence rather than legal procedure. The blow is an assertion of institutional power in the face of a challenge to its process.</p>',

    "23": '<p><strong>εἰ κακῶς ἐλάλησα, μαρτύρησον περὶ τοῦ κακοῦ</strong> — "If I spoke wrongly, testify about the wrong." <em>Kakōs</em> (G2560): wrongly, badly — moral or factual wrongness. The conditional is first class (<em>ei</em> + aorist indicative), treating the condition as factually stated without assuming its truth: "if I spoke wrongly (which I did not) — prove it." <strong>εἰ δὲ καλῶς, τί με δέρεις</strong> — "but if rightly, why do you strike me?" <em>Kalōs</em> (G2573): rightly, well. Jesus\' response to the blow is a demand for procedural justice: violence is not argumentation. The two conditionals — <em>kakōs / kalōs</em> — are clean legal logic rather than a refusal to cooperate.</p>',

    "24": '<p><strong>ἀπέστειλεν οὖν αὐτὸν ὁ Ἄννας δεδεμένον πρὸς Καϊάφαν τὸν ἀρχιερέα</strong> — "Annas therefore sent him bound to Caiaphas the high priest." <em>Dedemenon</em> — perfect passive participle, "bound/having been bound" — the binding from v. 12 is still in effect. Annas transfers jurisdiction to the official high priest for the formal proceedings. The brevity of the Evangelist\'s account of both preliminary hearings (the Synoptics give more detail of the Caiaphas proceedings) reflects the Fourth Gospel\'s focus: the theological weight of the trial falls on the Pilate exchange, not on the Jewish court.</p>',

    "25": '<p><strong>Μὴ καὶ σὺ ἐκ τῶν μαθητῶν αὐτοῦ εἶ</strong> — "You aren\'t also one of his disciples, are you?" The question form is identical to v. 17 — same <em>mē</em> construction anticipating denial — now from the servants and officials standing by the charcoal fire. Peter is asked to declare his allegiance in the very social group where belonging to Jesus would be most costly. <strong>ἠρνήσατο ἐκεῖνος καὶ εἶπεν· Οὐκ εἰμί</strong> — "he denied and said, I am not" — the same <em>ouk eimi</em> as v. 17. This is the second denial.</p>',

    "26": '<p><strong>εἷς ἐκ τῶν δούλων τοῦ ἀρχιερέως, συγγενὴς ὢν οὗ ἀπέκοψεν Πέτρος τὸ ὠτίον</strong> — "one of the high priest\'s servants, being a relative of the one whose ear Peter cut off." The third challenge is the most specific: a kinsman of Malchus, who presumably recognized Peter from the garden. The question — "Didn\'t I see you in the garden with him?" — is virtually an accusation; it has the force of an eyewitness identification. <em>Ouk egō se eidon</em> — "Did I not see you?" — double negative with <em>egō</em> for emphasis. Peter has no credible denial left; the kinship connection makes a lie nearly impossible to sustain.</p>',

    "27": '<p><strong>πάλιν οὖν ἠρνήσατο Πέτρος</strong> — "Peter denied again" — the third denial, narrated with minimal drama; the Evangelist\'s restraint is its own commentary. <strong>καὶ εὐθέως ἀλέκτωρ ἐφώνησεν</strong> — "and immediately a cock crowed." <em>Eutheōs</em> (G2112): immediately — the temporal marker confirms the fulfillment of Jesus\'s prediction (13:38: "before the rooster crows, you will deny me three times"). The cock crow is the structural endpoint of the Peter narrative in the passion; the Evangelist returns to the courtroom. The Johannine account of Peter\'s breakdown contains no weeping (contrast Matt 26:75; Luke 22:62) — Peter\'s restoration will come separately (21:15–19).</p>',

    "28": '<p><strong>ἄγουσιν τὸν Ἰησοῦν ἀπὸ τοῦ Καϊάφα εἰς τὸ πραιτώριον</strong> — "they lead Jesus from Caiaphas to the praetorium." <em>Praitōrion</em> (G4232): the Roman governor\'s official residence and judgment hall in Jerusalem — either the Antonia Fortress or Herod\'s Palace (scholars dispute). The Greek term transliterates the Latin <em>praetorium</em>. <strong>αὐτοὶ δὲ οὐκ εἰσῆλθον εἰς τὸ πραιτώριον, ἵνα μὴ μιανθῶσιν</strong> — "they themselves did not enter the praetorium, so that they might not be defiled." The defilement concern is Passover purity: contact with a Gentile dwelling (understood as containing leaven and perhaps corpse-impurity) would render them unable to eat the Passover meal. The irony the Evangelist deploys is sharp — they guard their ritual purity while handing over an innocent man to death. <em>Miainō</em> (G3392): to stain, defile.</p>',

    "29": '<p><strong>ἐξῆλθεν οὖν ὁ Πιλᾶτος ἔξω πρὸς αὐτούς</strong> — "Pilate therefore went outside to them." The spatial choreography of the trial — inside/outside the praetorium — is the Evangelist\'s structural device. Pilate must repeatedly cross the threshold because the accusers will not enter; the back-and-forth movements (vv. 29, 33, 38; 19:1, 4, 9, 13) dramatize the governor caught between Roman jurisdiction inside and Jewish pressure outside. <strong>Τίνα κατηγορίαν φέρετε κατὰ τοῦ ἀνθρώπου τούτου</strong> — "What accusation do you bring against this man?" — the standard Roman judicial opening: the accuser must state the charge.</p>',

    "30": '<p><strong>εἰ μὴ ἦν οὗτος κακοποιός, οὐκ ἄν σοι παρεδώκαμεν αὐτόν</strong> — "If this man were not a criminal, we would not have handed him over to you." The construction is second-class conditional (past contrary to fact): "if he were not [which he is]." The Jewish leaders do not actually state a charge — they assert the verdict and ask Pilate to ratify it. <em>Kakopoios</em> (G2555): evil-doer, criminal — a vague accusation that avoids the specifics they know Pilate would need to adjudicate.</p>',

    "31": '<p><strong>Λάβετε αὐτὸν ὑμεῖς καὶ κατὰ τὸν νόμον ὑμῶν κρίνατε αὐτόν</strong> — "Take him yourselves and judge him by your own law." Pilate\'s retort pushes the matter back: if the charge falls under Jewish law, Jewish courts should handle it. <strong>οὐκ ἔξεστιν ἡμῖν ἀποκτεῖναι οὐδένα</strong> — "it is not permitted for us to put anyone to death." <em>Exestin</em> (G1832): it is lawful, permitted — a legal claim about Roman provincial authority. Crucifixion (as opposed to stoning) was a Roman death-penalty; Rome had reserved capital punishment for itself in Judea (a debated but likely historical reality under the procuratorship). The Jewish leaders want crucifixion specifically, which only Pilate can authorize.</p>',

    "32": '<p><strong>ἵνα ὁ λόγος τοῦ Ἰησοῦ πληρωθῇ ὃν εἶπεν σημαίνων ποίῳ θανάτῳ ἤμελλεν ἀποθνῄσκειν</strong> — "that the word of Jesus might be fulfilled, which he spoke, signifying by what death he was going to die." The fulfillment notice applies to Jesus\'s own word — specifically the <em>hypsōthēnai</em> (being lifted up) sayings (3:14; 8:28; 12:32–33). <em>Sēmainō</em> (G4591): to signal, indicate — the same verb used in Rev 1:1 for symbolic revelation. Crucifixion is the "lifted up" death; stoning (the Jewish alternative) is not. The Evangelist\'s fulfillment formula here confirms that divine necessity governs the specific mode of execution.</p>',

    "33": '<p><strong>εἰσῆλθεν πάλιν εἰς τὸ πραιτώριον ὁ Πιλᾶτος καὶ ἐφώνησεν τὸν Ἰησοῦν</strong> — Pilate goes back inside and summons Jesus privately — the spatial movement marks the beginning of the interior hearing that will be the theological center of the trial. <strong>Σὺ εἶ ὁ βασιλεὺς τῶν Ἰουδαίων</strong> — "Are you the king of the Jews?" The question carries the political charge: a king of the Jews is a rival to Caesar and a threat to Roman order. <em>Basileus</em> (G935): king, ruler — in Pilate\'s mouth a political category; in Jesus\'s answer it will be redefined.</p>',

    "34": '<p><strong>Ἀφ᾽ ἑαυτοῦ σὺ τοῦτο λέγεις ἢ ἄλλοι εἶπόν σοι περὶ ἐμοῦ</strong> — "Do you say this from yourself, or did others tell you about me?" Jesus\'s counter-question is not evasion; it is a juridical clarification. The distinction between Roman and Jewish categories of "king" is decisive: if Pilate is asking about a political insurrectionist (his own concern), the answer is no; if he is repeating the Jewish leaders\' theological charge, the question needs reframing. Jesus forces Pilate to locate the question before answering it.</p>',

    "35": '<p><strong>Μήτι ἐγὼ Ἰουδαῖός εἰμι</strong> — "I am not a Jew, am I?" — <em>mēti</em> with <em>egō</em> emphatic: a scornful rhetorical question. Pilate disavows any stake in Jewish messianic categories. <strong>τὸ ἔθνος τὸ σὸν καὶ οἱ ἀρχιερεῖς παρέδωκάν σε ἐμοί</strong> — "Your own nation and the chief priests handed you over to me" — Pilate names the accusers and distances himself from their charge while acknowledging his own position as the decision-maker they require. <strong>τί ἐποίησας</strong> — "What have you done?" — Pilate\'s actual question: what is the concrete act being charged?</p>',

    "36": '<p><strong>ἡ βασιλεία ἡ ἐμὴ οὐκ ἔστιν ἐκ τοῦ κόσμου τούτου</strong> — "My kingdom is not from this world." The critical preposition: <em>ek tou kosmou toutou</em> — "out of / from this world" — marks origin and source, not location. Jesus is not claiming his kingdom does not operate within the world but that it does not derive from the world\'s power structures. <strong>εἰ ἐκ τοῦ κόσμου τούτου ἦν ἡ βασιλεία ἡ ἐμή, οἱ ὑπηρέται οἱ ἐμοὶ ἠγωνίζοντο ἄν</strong> — "if my kingdom were of this world, my servants would be fighting" — second-class conditional: contrary to fact. The test is armed resistance: world-kingdoms defend themselves by force. His servants are not fighting. <strong>ἡ βασιλεία ἡ ἐμὴ οὐκ ἔστιν ἐντεῦθεν</strong> — "my kingdom is not from here" — <em>enteuthen</em> (from here) closes the definition: the kingdom\'s source is elsewhere, its operation is therefore by different means.</p>',

    "37": '<p><strong>Οὐκοῦν βασιλεὺς εἶ σύ</strong> — "So you are a king!" — <em>oukoun</em> is an inferential particle: Pilate draws the conclusion from Jesus\'s own words. Jesus accepts the designation with a qualification: <strong>σὺ λέγεις ὅτι βασιλεύς εἰμι</strong> — "you say that I am a king" — neither full affirmation nor denial, but an acknowledgment that <em>the word</em> is Pilate\'s category and the reality it points to is Jesus\'s. <strong>ἐγὼ εἰς τοῦτο γεγέννημαι καὶ εἰς τοῦτο ἐλήλυθα εἰς τὸν κόσμον</strong> — "for this I have been born and for this I have come into the world" — perfect tenses: the birth and the coming are standing facts. The double purpose is truth-bearing: <strong>ἵνα μαρτυρήσω τῇ ἀληθείᾳ</strong> — "that I might witness to the truth." <em>Martyreō</em> (G3140): to witness, testify — the language of the law court now applied to Jesus\'s entire mission. <strong>πᾶς ὁ ὢν ἐκ τῆς ἀληθείας ἀκούει μου τῆς φωνῆς</strong> — "everyone who is of the truth hears my voice" — <em>ek tēs alētheias</em>: out of / deriving from truth — the same source-preposition as the kingdom in v. 36. Belonging to truth is an ontological status, not a moral achievement.</p>',

    "38": '<p><strong>Τί ἐστιν ἀλήθεια</strong> — "What is truth?" Pilate\'s famous question has been read as philosophical skepticism, rhetorical dismissal, weary pragmatism, or genuine inquiry. The Evangelist gives no answer — Pilate exits without waiting for one. The question lands in the reader\'s ear as the supreme irony of the trial: the one who is "the truth" (14:6) stands before the man who asks "what is truth?" and receives no answer because none is sought. <strong>οὐδεμίαν εὑρίσκω ἐν αὐτῷ αἰτίαν</strong> — "I find no charge/fault in him." <em>Aitia</em> (G156): cause, accusation, legal ground — Pilate\'s formal verdict of innocence is delivered three times in John (18:38; 19:4; 19:6). The repetition is juridically and theologically deliberate.</p>',

    "39": '<p><strong>ἔστιν δὲ συνήθεια ὑμῖν ἵνα ἕνα ἀπολύσω ὑμῖν ἐν τῷ πάσχα</strong> — "Now there is a custom for me to release one prisoner to you at the Passover." The <em>Passover amnesty</em> — the custom of releasing one prisoner at the feast — is attested in the Gospels (all four) but not in extra-biblical Jewish or Roman sources; scholars debate its historicity. The Evangelist\'s account uses it narratively to force the crowd into an explicit choice. <strong>βούλεσθε οὖν ἀπολύσω ὑμῖν τὸν βασιλέα τῶν Ἰουδαίων</strong> — "do you want me to release to you the king of the Jews?" — Pilate uses the royal title ironically and mockingly, but in doing so he names Jesus with the title that will go on the cross (19:19).</p>',

    "40": '<p><strong>ἐκραύγασαν οὖν πάλιν λέγοντες· Μὴ τοῦτον ἀλλὰ τὸν Βαραββᾶν</strong> — "They shouted again saying, Not this one but Barabbas." <em>Kraugazō</em> (G2905): to cry out loudly — a crowd shout, not deliberation. <strong>ἦν δὲ ὁ Βαραββᾶς λῃστής</strong> — "Now Barabbas was a robber/bandit." <em>Lēstēs</em> (G3027) is the same word used in 10:1 for the one who enters the sheepfold as a thief rather than through the gate. The Evangelist\'s word choice is not accidental: the crowd releases a <em>lēstēs</em> and crucifies the gate-giver, the shepherd. The name <em>Barabbas</em> — bar (son of) + abba (father) — adds another layer: they choose the son of a human father over the Son of the Father.</p>'
  }
}


def main():
    existing = load_comm('mkt-original', 'john')
    merge_comm(existing, JOHN)
    save_comm('mkt-original', 'john', existing)
    print('John 17–18 mkt-original written.')

if __name__ == '__main__':
    main()
